<template>
  <div>
    <vue-numeric-input id="style1" v-model="qty" :min="min" :max="max"></vue-numeric-input>
  </div>
</template>

<script>
import VueNumericInput from 'vue-numeric-input'

export default {
  props: {
    quantity: {
      type: [Number],
      required: true,
      default: 1
    },
    min: {
      type: [Number],
      default: 1
    },
    max: {
      type: [Number],
      default: 9999999
    },
  },
  name: "Quantity",
  data() {
    return {
      qty: this.quantity,
    }
  },
  components: {VueNumericInput}
}
</script>

<style>
#style1.vue-numeric-input {
 width: 120px!important;
}

#style1.vue-numeric-input .numeric-input {
  border: 0!important;
  text-align: center!important;
}

#style1.vue-numeric-input .numeric-input:focus {
  outline: 0!important;
}

#style1.vue-numeric-input .btn {
  border-radius: 100px;
  height: 30px;
  width: 30px;
  margin-top: -5px;
  font-size: 12px;
}
</style>
